<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Media\EquipmentLayers\EquipmentLayerAssetService;use App\Domain\Media\EquipmentLayers\EquipmentLayerException;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\ItemVisualAssetRequest;use App\Models\Item;use App\Models\ItemVisualAsset;
final class ItemVisualAssetController extends Controller{public function store(ItemVisualAssetRequest $request,Item $item,EquipmentLayerAssetService $service){try{$service->replace($item,$request->input('body_type'),$request->input('visual_slot'),$request->file('equipment_layer'));return back()->with('status','Apariencia equipada actualizada.');}catch(EquipmentLayerException $e){return back()->withInput()->withErrors(['equipment_layer'=>$e->getMessage()]);}}public function destroy(Item $item,ItemVisualAsset $itemVisualAsset,EquipmentLayerAssetService $service){$service->delete($item,$itemVisualAsset);return back()->with('status','Capa equipada eliminada.');}}
